#ifndef DECODE_KERNEL_H
#define DECODE_KERNEL_H

#include <stdint.h>
#include <ap_int.h>

// Kernel prototype
extern "C" void decode_kernel(
    const ap_uint<64>* input_data,
    const int layer_size,
    const float layer_stride,
	float out_boxes_x[],
	float out_boxes_y[],
	float out_boxes_w[],
	float out_boxes_h[],
	int out_cls[],
	float out_score[],
	int out_box_num
);

