// decode_kernel.cpp

#include <hls_stream.h>
#include <ap_int.h>
#include <ap_fixed.h>
#include <math.h>
#include <stdint.h>
#include <string.h>

#include "decode_kernel.h"

// ---------- Configurable limits (tune for your design) ----------FZ
// #define MAX_INPUT       2680000
#define MAX_BOXES         2048   // max number of total boxes before NMS
#define DIST_BINS          16    // 16 bins in distance softmax branch
#define NUM_CLASSES        3
#define OUTPUT_DIM         67
// ----------------------------------------------------------------

// Kernel top-level
extern "C" {

void decode_kernel(
  const ap_uint<64> *input_data,         // big contiguous memory containing layer outputs
  const int   layer_size,           // offsets (in bytes or elements) for each layer in input_data (length num_layers)
  const float layer_stride,         // stride per layer
  float out_boxes_x[MAX_BOXES],
  float out_boxes_y[MAX_BOXES],
  float out_boxes_w[MAX_BOXES],
  float out_boxes_h[MAX_BOXES],
  int out_cls[MAX_BOXES],
  float out_score[MAX_BOXES],
  int out_box_num                  // number of boxes actually written (scalar on host)
)
{

// #pragma HLS INTERFACE m_axi port=input_data   offset=slave bundle=gmem0 depth=2680000
#pragma HLS INTERFACE m_axi port=input_data   offset=slave bundle=gmem0 depth=335000

#pragma HLS INTERFACE m_axi port=out_boxes_x      offset=slave bundle=gmem1 depth=2048
#pragma HLS INTERFACE m_axi port=out_boxes_y      offset=slave bundle=gmem1 depth=2048
#pragma HLS INTERFACE m_axi port=out_boxes_w      offset=slave bundle=gmem1 depth=2048
#pragma HLS INTERFACE m_axi port=out_boxes_h      offset=slave bundle=gmem1 depth=2048
#pragma HLS INTERFACE m_axi port=out_cls          offset=slave bundle=gmem1 depth=2048
#pragma HLS INTERFACE m_axi port=out_score        offset=slave bundle=gmem1 depth=2048

#pragma HLS INTERFACE s_axilite port=layer_size
#pragma HLS INTERFACE s_axilite port=layer_stride
#pragma HLS INTERFACE s_axilite port=out_box_num 
#pragma HLS INTERFACE s_axilite port=return

  int total_boxes = 0;
  out_box_num = 0;
  int sizeOut = layer_size * layer_size;
  const float det_scale = 0.1f; 
  const float conf_thresh = 0.9f;  
  float ct = -logf(1.0f / conf_thresh - 1.0f) / det_scale;
  int32_t conf_thresh_inverse = (int32_t)floorf(ct);

  float local_boxes_x[MAX_BOXES];
